import ScopedPageContent from '../components/ScopedPageContent';

const pageCss = ":root{\n    --bg:           #F8F9FA;\n    --bg-alt:       #FAFAF8;\n    --heading:      #2D3748;\n    --body:         #4A5568;\n    --muted:        #718096;\n    --accent-soft:  #8FBC8F;\n    --line:         #B38B6D;\n    --line-soft:    rgba(179, 139, 109, .28);\n    --line-faint:   rgba(45, 55, 72, .08);\n    --cta:          #576DB5;\n    --cta-hover:    #46599C;\n    --link:         #1E3A8A;\n    --font: 'Plus Jakarta Sans', system-ui, -apple-system, Segoe UI, sans-serif;\n    --max: 1320px;\n    --gutter: 24px;\n    --pad: clamp(20px, 4vw, 48px);\n  }\n\n  *{ box-sizing:border-box; }\n  html,body{ margin:0; padding:0; }\n  body{\n    background: var(--bg);\n    color: var(--body);\n    font-family: var(--font);\n    font-size: 16px; line-height: 1.6;\n    -webkit-font-smoothing: antialiased;\n    text-rendering: optimizeLegibility;\n    overflow-x: hidden;\n  }\n  a{ color: inherit; text-decoration: none; }\n  button{ font-family: inherit; cursor: pointer; border: 0; background: transparent; }\n\n  /* ============ NAV ============ */\n  .nav-wrap{\n    position:sticky; top:0; z-index:50;\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    background: rgba(248, 249, 250, .72);\n    border-bottom: 1px solid var(--line-soft);\n  }\n  .container{\n    max-width: var(--max);\n    margin: 0 auto;\n    padding-left: var(--pad);\n    padding-right: var(--pad);\n    position: relative;\n  }\n  .nav{\n    display:grid; grid-template-columns: auto 1fr auto;\n    align-items:center; height:78px; gap:32px;\n  }\n  .logo{ display:flex; align-items:center; height:40px; }\n  .logo img{ height:38px; width:auto; display:block; }\n  .menu{ display:flex; justify-content:center; gap:6px; }\n  .menu a, .menu button.menu-link{\n    position:relative;\n    display:inline-flex; align-items:center; gap:6px;\n    padding:10px 14px;\n    font-size:14.5px; font-weight:500;\n    color:var(--body); border-radius:8px;\n    transition: color .2s ease, background .2s ease;\n  }\n  .menu a:hover, .menu button.menu-link:hover{ color:var(--heading); background: rgba(179,139,109,.06); }\n  .menu a::after{\n    content:\"\"; position:absolute; left:14px; right:14px; bottom:6px;\n    height:1px; background:var(--line); transform:scaleX(0); transform-origin:left;\n    transition: transform .25s ease;\n  }\n  .menu a:hover::after, .menu a.is-active::after{ transform:scaleX(1); }\n  .menu a.is-active, .menu button.menu-link.is-active{ color: var(--heading); }\n  .menu button.menu-link.is-active::after{\n    content:\"\"; position:absolute; left:14px; right:14px; bottom:6px;\n    height:1px; background:var(--line); transform:scaleX(1);\n  }\n  .menu .chev{ width:12px; height:12px; color:var(--muted); }\n\n  .nav-right{ display:flex; align-items:center; gap:8px; }\n  .lang{\n    display:inline-flex; align-items:center; gap:6px;\n    padding: 9px 12px;\n    font-size:13.5px; font-weight:600;\n    color:var(--body);\n    border:1px solid var(--line-soft);\n    border-radius: 999px;\n    background: rgba(255,255,255,.5);\n    transition: border-color .2s, color .2s, background .2s;\n  }\n  .lang:hover{ border-color:var(--line); color:var(--heading); background:#fff; }\n  .lang .globe{ color:var(--line); }\n  .lang .chev{ color:var(--muted); }\n  .icon-btn{\n    width:40px; height:40px;\n    display:grid; place-items:center;\n    border-radius:50%;\n    border:1px solid var(--line-soft);\n    color:var(--body);\n    background: rgba(255,255,255,.5);\n    transition: border-color .2s, color .2s, background .2s;\n  }\n  .icon-btn:hover{ border-color:var(--line); color:var(--heading); background:#fff; }\n\n  /* ============ PRICING HERO ============ */\n  .pr-hero{\n    position: relative;\n    background: var(--bg);\n    padding: clamp(20px, 2.4vw, 32px) 0 clamp(14px, 1.8vw, 22px);\n    overflow: hidden;\n    border-bottom: 1px solid var(--line-faint);\n  }\n  .pr-hero::before{\n    content:\"\";\n    position: absolute; inset: 0;\n    background:\n      radial-gradient(900px 480px at 88% 12%, rgba(143,188,143,.12), transparent 65%),\n      radial-gradient(720px 480px at 12% 92%, rgba(179,139,109,.08), transparent 70%);\n    pointer-events: none;\n  }\n\n  .pr-trail{\n    display: flex; align-items: center; justify-content: space-between;\n    gap: 16px;\n    padding-bottom: 14px;\n    margin-bottom: 0;\n    border-bottom: 1px solid var(--line-faint);\n    font-size: 11.5px;\n    font-weight: 600;\n    color: var(--muted);\n    position: relative;\n    flex-wrap: wrap;\n  }\n  .pr-trail-left{\n    display: flex; align-items: center; gap: 8px;\n  }\n  .pr-trail a{ color: var(--muted); transition: color .2s; }\n  .pr-trail a:hover{ color: var(--heading); }\n  .pr-trail svg{ color: var(--line); opacity: .7; }\n  .pr-trail .here{ color: var(--heading); font-weight: 700; }\n\n  .pr-hero-grid{\n    display: grid;\n    grid-template-columns: repeat(12, 1fr);\n    gap: var(--gutter);\n    align-items: end;\n    position: relative;\n  }\n  .pr-eyebrow{\n    display: inline-flex; align-items: center; gap: 10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: var(--muted);\n    padding: 7px 14px;\n    background: rgba(255,255,255,.65);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    max-width: max-content;\n    margin: 0;\n    flex: 0 0 auto;\n  }\n  .pr-eyebrow::before{\n    content:\"\"; width: 7px; height: 7px; border-radius: 50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 0 4px rgba(143,188,143,.20);\n  }\n\n  .pr-h1{\n    grid-column: 1 / span 8;\n    font-size: clamp(40px, 5.4vw, 76px);\n    line-height: 1.02;\n    letter-spacing: -0.030em;\n    color: var(--heading);\n    font-weight: 700;\n    margin: 0 0 24px;\n    max-width: 18ch;\n    text-wrap: balance;\n  }\n  .pr-h1 .accent{\n    position: relative;\n    display: inline-block;\n    color: var(--heading);\n  }\n  .pr-h1 .accent::before{\n    content:\"\";\n    position: absolute;\n    left: -2px; right: -2px;\n    bottom: 0.06em;\n    height: 14px;\n    background: linear-gradient(90deg, rgba(179,139,109,.32), rgba(143,188,143,.30));\n    border-radius: 3px;\n    z-index: -1;\n    transform: skewX(-6deg);\n  }\n\n  .pr-hero-sub{\n    grid-column: 1 / -1;\n    display: grid;\n    grid-template-columns: repeat(12, 1fr);\n    gap: var(--gutter);\n    align-items: end;\n    padding-top: 24px;\n    border-top: 1px solid var(--line-faint);\n  }\n  .pr-meta{\n    grid-column: 1 / span 5;\n    display: flex; align-items: center; gap: 14px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--muted);\n  }\n  .pr-meta .bar{\n    flex: 1;\n    height: 1px;\n    background: var(--line-faint);\n    max-width: 220px;\n  }\n  .pr-lede{\n    grid-column: 7 / -1;\n    font-size: clamp(15px, 1.2vw, 17px);\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    max-width: 56ch;\n    font-weight: 500;\n  }\n\n  /* ============ INVESTMENT INCLUDES ============ */\n  .pr-includes{\n    background: var(--bg-alt);\n    padding: clamp(72px, 9vw, 128px) 0;\n    border-bottom: 1px solid var(--line-faint);\n    position: relative;\n    overflow: hidden;\n  }\n  .pr-includes::before{\n    content:\"\";\n    position: absolute; inset: 0;\n    background:\n      radial-gradient(800px 420px at 92% 8%, rgba(143,188,143,.06), transparent 70%),\n      radial-gradient(620px 320px at 8% 92%, rgba(179,139,109,.05), transparent 70%);\n    pointer-events: none;\n  }\n  .pr-section-head{\n    display: grid;\n    grid-template-columns: repeat(12, 1fr);\n    gap: var(--gutter);\n    align-items: end;\n    margin-bottom: clamp(32px, 4vw, 48px);\n  }\n  .pr-section-eyebrow{\n    grid-column: 1 / -1;\n    display: inline-flex; align-items: center; gap: 10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 18px;\n  }\n  .pr-section-eyebrow::before{\n    content:\"\"; width: 7px; height: 7px; border-radius: 50%;\n    background: var(--accent-soft);\n  }\n  .pr-section-h2{\n    grid-column: 1 / span 7;\n    font-size: clamp(32px, 4vw, 52px);\n    line-height: 1.04;\n    letter-spacing: -0.025em;\n    color: var(--heading);\n    font-weight: 700;\n    margin: 0;\n    max-width: 18ch;\n    text-wrap: balance;\n  }\n  .pr-section-sub{\n    grid-column: 9 / -1;\n    font-size: 15.5px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    padding-bottom: 8px;\n  }\n\n  .pr-includes-grid{\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: clamp(16px, 2vw, 22px);\n  }\n  .pr-include-card{\n    position: relative;\n    padding: clamp(24px, 2.6vw, 32px);\n    background: rgba(255,255,255,.65);\n    backdrop-filter: blur(12px) saturate(140%);\n    -webkit-backdrop-filter: blur(12px) saturate(140%);\n    border: 1px solid var(--line-soft);\n    border-radius: 18px;\n    overflow: hidden;\n    isolation: isolate;\n    transition: transform .35s cubic-bezier(.2,.7,.2,1), border-color .3s, box-shadow .3s, background .3s;\n  }\n  .pr-include-card::before{\n    content:\"\";\n    position: absolute;\n    top: 0; left: 0; right: 0;\n    height: 3px;\n    background: linear-gradient(90deg, var(--line) 0%, var(--accent-soft) 100%);\n    transform: scaleX(0);\n    transform-origin: left;\n    transition: transform .55s cubic-bezier(.2,.7,.2,1);\n  }\n  .pr-include-card:hover{\n    transform: translateY(-4px);\n    border-color: var(--line);\n    background: #fff;\n    box-shadow: 0 32px 64px -32px rgba(179,139,109,.40);\n  }\n  .pr-include-card:hover::before{ transform: scaleX(1); }\n\n  .pr-include-icon{\n    width: 48px; height: 48px;\n    border-radius: 12px;\n    background: rgba(87,109,181,.14);\n    color: var(--cta);\n    display: grid; place-items: center;\n    margin-bottom: 16px;\n    transition: background .3s, transform .35s;\n  }\n  .pr-include-card:nth-child(2) .pr-include-icon{ background: rgba(143,188,143,.18); color: var(--accent-soft); }\n  .pr-include-card:nth-child(3) .pr-include-icon{ background: rgba(179,139,109,.18); color: var(--line); }\n  .pr-include-card:hover .pr-include-icon{ transform: rotate(-6deg) scale(1.06); }\n\n  .pr-include-tag{\n    display: inline-flex; align-items: center; gap: 6px;\n    font-size: 10.5px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 8px;\n  }\n  .pr-include-tag::before{\n    content:\"\"; width: 5px; height: 5px;\n    border-radius: 50%;\n    background: var(--cta);\n  }\n  .pr-include-card:nth-child(2) .pr-include-tag::before{ background: var(--accent-soft); }\n  .pr-include-card:nth-child(3) .pr-include-tag::before{ background: var(--line); }\n\n  .pr-include-title{\n    font-size: clamp(18px, 1.6vw, 22px);\n    font-weight: 700;\n    line-height: 1.2;\n    letter-spacing: -0.018em;\n    color: var(--heading);\n    margin: 0 0 10px;\n    max-width: 22ch;\n  }\n  .pr-include-text{\n    font-size: 14px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0 0 16px;\n    font-weight: 500;\n  }\n  .pr-include-text a{\n    color: var(--cta);\n    font-weight: 600;\n    border-bottom: 1px solid transparent;\n    transition: border-color .2s;\n  }\n  .pr-include-text a:hover{ border-bottom-color: currentColor; }\n\n  .pr-include-list{\n    list-style: none;\n    margin: 0; padding: 14px 0 0;\n    border-top: 1px solid var(--line-faint);\n    display: flex; flex-direction: column;\n    gap: 8px;\n  }\n  .pr-include-list li{\n    display: flex; align-items: flex-start; gap: 8px;\n    font-size: 13px;\n    color: var(--body);\n    line-height: 1.5;\n    font-weight: 500;\n  }\n  .pr-include-list li .check{\n    width: 16px; height: 16px;\n    border-radius: 50%;\n    background: rgba(143,188,143,.20);\n    color: var(--accent-soft);\n    display: grid; place-items: center;\n    flex: 0 0 16px;\n    margin-top: 2px;\n  }\n\n  /* ============ ROI / AUTOMATION QUANT ============ */\n  .pr-roi{\n    background: var(--bg);\n    padding: clamp(72px, 9vw, 128px) 0;\n    border-bottom: 1px solid var(--line-faint);\n    position: relative;\n    overflow: hidden;\n  }\n\n  .pr-roi-grid{\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: clamp(32px, 4vw, 64px);\n    align-items: center;\n  }\n  .pr-roi-text{\n    display: flex; flex-direction: column;\n    gap: 18px;\n  }\n  .pr-roi-eyebrow{\n    display: inline-flex; align-items: center; gap: 10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: var(--muted);\n  }\n  .pr-roi-eyebrow::before{\n    content:\"\"; width: 7px; height: 7px; border-radius: 50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 0 4px rgba(143,188,143,.20);\n  }\n  .pr-roi-h2{\n    font-size: clamp(28px, 3.6vw, 48px);\n    line-height: 1.04;\n    letter-spacing: -0.025em;\n    color: var(--heading);\n    font-weight: 700;\n    margin: 0;\n    max-width: 18ch;\n    text-wrap: balance;\n  }\n  .pr-roi-text p{\n    font-size: 15px;\n    line-height: 1.7;\n    color: var(--body);\n    margin: 0;\n    max-width: 56ch;\n    font-weight: 500;\n  }\n  .pr-roi-text p strong{ color: var(--heading); font-weight: 700; }\n\n  /* RIGHT: 4 stat cards in 2x2 grid */\n  .pr-roi-stats{\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: clamp(12px, 1.4vw, 16px);\n  }\n  .pr-stat{\n    position: relative;\n    padding: clamp(20px, 2.2vw, 28px);\n    background: rgba(255,255,255,.65);\n    backdrop-filter: blur(12px) saturate(140%);\n    -webkit-backdrop-filter: blur(12px) saturate(140%);\n    border: 1px solid var(--line-soft);\n    border-radius: 16px;\n    overflow: hidden;\n    isolation: isolate;\n    transition: transform .35s cubic-bezier(.2,.7,.2,1), border-color .3s, box-shadow .3s, background .3s;\n  }\n  .pr-stat::before{\n    content:\"\";\n    position: absolute;\n    top: 0; left: 0; bottom: 0;\n    width: 3px;\n    background: linear-gradient(180deg, var(--cta) 0%, var(--accent-soft) 100%);\n    transform: scaleY(0);\n    transform-origin: top;\n    transition: transform .45s cubic-bezier(.2,.7,.2,1);\n  }\n  .pr-stat:hover{\n    transform: translateY(-4px);\n    border-color: var(--line);\n    background: #fff;\n    box-shadow: 0 24px 48px -28px rgba(179,139,109,.40);\n  }\n  .pr-stat:hover::before{ transform: scaleY(1); }\n  .pr-stat:nth-child(2)::before{ background: linear-gradient(180deg, var(--accent-soft) 0%, var(--line) 100%); }\n  .pr-stat:nth-child(3)::before{ background: linear-gradient(180deg, var(--line) 0%, var(--cta) 100%); }\n  .pr-stat:nth-child(4)::before{ background: linear-gradient(180deg, var(--accent-soft) 0%, var(--cta) 100%); }\n\n  .pr-stat-icon{\n    width: 36px; height: 36px;\n    border-radius: 10px;\n    background: rgba(87,109,181,.14);\n    color: var(--cta);\n    display: grid; place-items: center;\n    margin-bottom: 14px;\n    transition: transform .35s;\n  }\n  .pr-stat:nth-child(2) .pr-stat-icon{ background: rgba(143,188,143,.18); color: var(--accent-soft); }\n  .pr-stat:nth-child(3) .pr-stat-icon{ background: rgba(179,139,109,.18); color: var(--line); }\n  .pr-stat:nth-child(4) .pr-stat-icon{ background: rgba(143,188,143,.18); color: var(--accent-soft); }\n  .pr-stat:hover .pr-stat-icon{ transform: rotate(-8deg) scale(1.06); }\n\n  .pr-stat-num{\n    font-size: clamp(24px, 2.8vw, 36px);\n    font-weight: 700;\n    line-height: 1;\n    letter-spacing: -0.025em;\n    color: var(--heading);\n    margin-bottom: 6px;\n  }\n  .pr-stat-num em{\n    font-style: normal;\n    color: var(--cta);\n  }\n  .pr-stat:nth-child(2) .pr-stat-num em{ color: var(--accent-soft); }\n  .pr-stat:nth-child(3) .pr-stat-num em{ color: var(--line); }\n\n  .pr-stat-label{\n    font-size: 13px;\n    font-weight: 700;\n    letter-spacing: -0.01em;\n    color: var(--heading);\n    margin: 0 0 6px;\n    line-height: 1.3;\n  }\n  .pr-stat-text{\n    font-size: 12.5px;\n    line-height: 1.5;\n    color: var(--body);\n    margin: 0;\n    font-weight: 500;\n  }\n\n  /* ============ PRICING TIERS ============ */\n  .pr-tiers{\n    background: var(--bg-alt);\n    padding: clamp(28px, 3.4vw, 48px) 0 clamp(72px, 9vw, 128px);\n    border-bottom: 1px solid var(--line-faint);\n    position: relative;\n    overflow: hidden;\n  }\n  .pr-tiers::before{\n    content:\"\";\n    position: absolute; inset: 0;\n    background:\n      radial-gradient(800px 420px at 92% 8%, rgba(87,109,181,.05), transparent 70%),\n      radial-gradient(620px 320px at 8% 94%, rgba(143,188,143,.06), transparent 70%);\n    pointer-events: none;\n  }\n\n  .pr-tiers-grid{\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: clamp(18px, 2.2vw, 24px);\n    align-items: stretch;\n  }\n\n  .pr-tier{\n    position: relative;\n    display: flex; flex-direction: column;\n    padding: clamp(28px, 3vw, 40px);\n    background: rgba(255,255,255,.75);\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    border: 1px solid var(--line-soft);\n    border-radius: 24px;\n    overflow: hidden;\n    isolation: isolate;\n    transition: transform .35s cubic-bezier(.2,.7,.2,1), border-color .35s, box-shadow .35s, background .35s;\n  }\n  .pr-tier::before{\n    content:\"\";\n    position: absolute;\n    top: 0; left: 0; right: 0;\n    height: 3px;\n    background: linear-gradient(90deg, var(--line) 0%, var(--accent-soft) 100%);\n    transform: scaleX(0);\n    transform-origin: left;\n    transition: transform .55s cubic-bezier(.2,.7,.2,1);\n  }\n  .pr-tier:hover{\n    transform: translateY(-6px);\n    border-color: var(--line);\n    background: #fff;\n    box-shadow: 0 40px 80px -40px rgba(179,139,109,.45);\n  }\n  .pr-tier:hover::before{ transform: scaleX(1); }\n\n  /* Featured tier (Growth Pro) — solid CTA-blue */\n  .pr-tier.is-featured{\n    background: linear-gradient(180deg, var(--cta) 0%, var(--cta-hover) 100%);\n    border-color: rgba(255,255,255,.20);\n    color: #fff;\n    transform: scale(1.02);\n  }\n  .pr-tier.is-featured::before{\n    background: linear-gradient(90deg, rgba(255,255,255,.7), rgba(143,188,143,.7));\n  }\n  .pr-tier.is-featured::after{\n    content:\"\";\n    position: absolute; inset: 0;\n    background:\n      radial-gradient(420px 220px at 92% 8%, rgba(143,188,143,.18), transparent 65%),\n      radial-gradient(320px 200px at 8% 94%, rgba(179,139,109,.14), transparent 70%);\n    pointer-events: none;\n    z-index: 0;\n  }\n  .pr-tier.is-featured > *{ position: relative; z-index: 1; }\n  .pr-tier.is-featured:hover{\n    background: linear-gradient(180deg, var(--cta-hover) 0%, #3A4DA0 100%);\n    transform: translateY(-6px) scale(1.02);\n    box-shadow: 0 40px 80px -40px rgba(87,109,181,.55);\n  }\n\n  .pr-tier-badge{\n    position: absolute;\n    top: 22px; right: 22px;\n    z-index: 2;\n    display: inline-flex; align-items: center; gap: 6px;\n    padding: 6px 12px 6px 10px;\n    background: rgba(255,255,255,.92);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    font-size: 10px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--heading);\n  }\n  .pr-tier-badge::before{\n    content:\"\"; width: 5px; height: 5px;\n    border-radius: 50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 0 3px rgba(143,188,143,.20);\n  }\n\n  .pr-tier-name{\n    font-size: 15px;\n    font-weight: 700;\n    color: var(--heading);\n    letter-spacing: -0.012em;\n    margin: 0 0 14px;\n    display: inline-flex; align-items: center; gap: 8px;\n  }\n  .pr-tier.is-featured .pr-tier-name{ color: rgba(255,255,255,.85); }\n  .pr-tier-name::before{\n    content:\"\"; width: 6px; height: 6px;\n    border-radius: 50%;\n    background: var(--cta);\n  }\n  .pr-tier:nth-child(1) .pr-tier-name::before{ background: var(--accent-soft); }\n  .pr-tier:nth-child(3) .pr-tier-name::before{ background: var(--line); }\n  .pr-tier.is-featured .pr-tier-name::before{ background: #fff; }\n\n  .pr-tier-price{\n    display: flex; align-items: baseline; gap: 8px;\n    margin-bottom: 10px;\n  }\n  .pr-tier-amount{\n    font-size: clamp(36px, 4.4vw, 52px);\n    font-weight: 700;\n    color: var(--heading);\n    letter-spacing: -0.030em;\n    line-height: 1;\n  }\n  .pr-tier.is-featured .pr-tier-amount{ color: #fff; }\n  .pr-tier-period{\n    font-size: 14px;\n    color: var(--muted);\n    font-weight: 600;\n  }\n  .pr-tier.is-featured .pr-tier-period{ color: rgba(255,255,255,.70); }\n\n  .pr-tier-tagline{\n    font-size: 14px;\n    line-height: 1.55;\n    color: var(--body);\n    margin: 0 0 18px;\n    font-weight: 500;\n    max-width: 36ch;\n  }\n  .pr-tier.is-featured .pr-tier-tagline{ color: rgba(255,255,255,.82); }\n\n  .pr-tier-bestfor{\n    padding: 14px 0;\n    border-top: 1px solid var(--line-faint);\n    border-bottom: 1px solid var(--line-faint);\n    margin-bottom: 18px;\n  }\n  .pr-tier.is-featured .pr-tier-bestfor{\n    border-top-color: rgba(255,255,255,.20);\n    border-bottom-color: rgba(255,255,255,.20);\n  }\n  .pr-tier-bestfor-label{\n    display: block;\n    font-size: 10.5px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 4px;\n  }\n  .pr-tier.is-featured .pr-tier-bestfor-label{ color: rgba(255,255,255,.65); }\n  .pr-tier-bestfor-text{\n    display: block;\n    font-size: 13px;\n    color: var(--heading);\n    font-weight: 600;\n    line-height: 1.4;\n  }\n  .pr-tier.is-featured .pr-tier-bestfor-text{ color: #fff; }\n\n  .pr-tier-cta{\n    display: inline-flex; align-items: center; justify-content: center; gap: 10px;\n    padding: 13px 22px;\n    background: var(--cta);\n    color: #fff;\n    font-size: 13.5px;\n    font-weight: 600;\n    letter-spacing: -0.005em;\n    border-radius: 999px;\n    margin-bottom: 22px;\n    transition: background .25s, transform .25s, box-shadow .3s;\n    box-shadow: 0 12px 32px -10px rgba(87,109,181,.50);\n  }\n  .pr-tier-cta:hover{\n    background: var(--cta-hover);\n    transform: translateY(-2px);\n    box-shadow: 0 18px 42px -10px rgba(87,109,181,.65);\n  }\n  .pr-tier-cta svg{ transition: transform .3s; }\n  .pr-tier-cta:hover svg{ transform: translateX(2px); }\n  .pr-tier.is-featured .pr-tier-cta{\n    background: #fff;\n    color: var(--cta);\n    box-shadow: 0 12px 32px -10px rgba(0,0,0,.15);\n  }\n  .pr-tier.is-featured .pr-tier-cta:hover{\n    background: var(--bg-alt);\n    color: var(--cta-hover);\n    box-shadow: 0 18px 42px -10px rgba(0,0,0,.20);\n  }\n\n  .pr-tier-section-label{\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 12px;\n    display: inline-flex; align-items: center; gap: 6px;\n  }\n  .pr-tier-section-label::before{\n    content:\"\"; width: 5px; height: 5px;\n    border-radius: 50%;\n    background: var(--accent-soft);\n  }\n  .pr-tier.is-featured .pr-tier-section-label{ color: rgba(255,255,255,.65); }\n  .pr-tier.is-featured .pr-tier-section-label::before{ background: var(--accent-soft); }\n\n  .pr-tier-list{\n    list-style: none;\n    margin: 0 0 18px; padding: 0;\n    display: flex; flex-direction: column;\n    gap: 10px;\n  }\n  .pr-tier-list li{\n    display: flex; align-items: flex-start; gap: 10px;\n    font-size: 13.5px;\n    color: var(--body);\n    line-height: 1.5;\n    font-weight: 500;\n  }\n  .pr-tier.is-featured .pr-tier-list li{ color: rgba(255,255,255,.85); }\n  .pr-tier-list li .check{\n    width: 18px; height: 18px;\n    border-radius: 50%;\n    background: rgba(143,188,143,.20);\n    color: var(--accent-soft);\n    display: grid; place-items: center;\n    flex: 0 0 18px;\n    margin-top: 1px;\n  }\n  .pr-tier.is-featured .pr-tier-list li .check{\n    background: rgba(255,255,255,.20);\n    color: #fff;\n  }\n  .pr-tier-list.is-not li .x{\n    width: 18px; height: 18px;\n    border-radius: 50%;\n    background: rgba(45,55,72,.06);\n    color: var(--muted);\n    display: grid; place-items: center;\n    flex: 0 0 18px;\n    margin-top: 1px;\n  }\n  .pr-tier.is-featured .pr-tier-list.is-not li{ color: rgba(255,255,255,.55); }\n  .pr-tier.is-featured .pr-tier-list.is-not li .x{\n    background: rgba(255,255,255,.10);\n    color: rgba(255,255,255,.55);\n  }\n\n  .pr-tier-divider{\n    height: 1px;\n    background: var(--line-faint);\n    margin: 18px 0;\n  }\n  .pr-tier.is-featured .pr-tier-divider{ background: rgba(255,255,255,.20); }\n\n  /* ============ COMPARISON TABLE ============ */\n  .pr-compare{\n    background: var(--bg);\n    padding: clamp(72px, 9vw, 128px) 0;\n    border-bottom: 1px solid var(--line-faint);\n    position: relative;\n    overflow: hidden;\n  }\n\n  .pr-compare-wrap{\n    background: rgba(255,255,255,.65);\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    border: 1px solid var(--line-soft);\n    border-radius: 24px;\n    overflow: hidden;\n  }\n\n  .pr-table{\n    width: 100%;\n    border-collapse: collapse;\n    font-size: 14px;\n  }\n  .pr-table thead{\n    background: rgba(248,249,250,.6);\n  }\n  .pr-table thead th{\n    padding: 22px 18px;\n    text-align: left;\n    font-size: 11.5px;\n    font-weight: 700;\n    letter-spacing: .14em;\n    text-transform: uppercase;\n    color: var(--muted);\n    border-bottom: 1px solid var(--line-faint);\n    vertical-align: bottom;\n  }\n  .pr-table thead th:not(:first-child){ text-align: center; }\n  .pr-table thead th .col-name{\n    display: block;\n    font-size: 16px;\n    font-weight: 700;\n    color: var(--heading);\n    letter-spacing: -0.015em;\n    text-transform: none;\n    margin-bottom: 4px;\n  }\n  .pr-table thead th.is-featured .col-name{ color: var(--cta); }\n  .pr-table thead th .col-price{\n    display: block;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .14em;\n    text-transform: uppercase;\n    color: var(--muted);\n  }\n\n  .pr-table tbody tr{\n    transition: background .25s;\n  }\n  .pr-table tbody tr:hover{\n    background: rgba(143,188,143,.06);\n  }\n  .pr-table tbody td{\n    padding: 14px 18px;\n    border-bottom: 1px solid var(--line-faint);\n    color: var(--body);\n    font-weight: 500;\n    vertical-align: middle;\n  }\n  .pr-table tbody tr:last-child td{ border-bottom: 0; }\n  .pr-table tbody td:first-child{\n    color: var(--heading);\n    font-weight: 600;\n  }\n  .pr-table tbody td:not(:first-child){\n    text-align: center;\n    width: 16%;\n  }\n  .pr-table tbody td.is-featured-col{\n    background: rgba(87,109,181,.04);\n  }\n\n  .pr-cell-check{\n    display: inline-grid; place-items: center;\n    width: 24px; height: 24px;\n    border-radius: 50%;\n    background: rgba(143,188,143,.20);\n    color: var(--accent-soft);\n  }\n  .pr-cell-dash{\n    color: var(--muted);\n    font-size: 18px;\n    font-weight: 600;\n    opacity: .5;\n  }\n\n  /* Section divider rows */\n  .pr-table tbody tr.is-divider td{\n    background: rgba(248,249,250,.5);\n    padding: 14px 18px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--muted);\n    border-bottom: 1px solid var(--line-faint);\n  }\n  .pr-table tbody tr.is-divider td:not(:first-child){ background: rgba(248,249,250,.5); }\n\n  /* Final CTA banner */\n  .pr-cta{\n    background: var(--bg);\n    padding: clamp(56px, 7vw, 96px) 0 clamp(72px, 9vw, 128px);\n    position: relative;\n  }\n  .pr-cta-card{\n    position: relative;\n    border-radius: 32px;\n    overflow: hidden;\n    isolation: isolate;\n    padding: clamp(56px, 7vw, 96px) clamp(28px, 4vw, 64px);\n    background: linear-gradient(180deg, #2D3748 0%, #1F2837 100%);\n    box-shadow: 0 40px 100px -50px rgba(45,55,72,.40);\n    text-align: center;\n  }\n  .pr-cta-card::before{\n    content:\"\";\n    position: absolute; inset: 0;\n    background:\n      radial-gradient(680px 360px at 88% 12%, rgba(143,188,143,.18), transparent 70%),\n      radial-gradient(620px 320px at 8% 92%, rgba(179,139,109,.14), transparent 70%);\n    pointer-events: none;\n    z-index: 0;\n  }\n  .pr-cta-card > *{ position: relative; z-index: 1; }\n  .pr-cta-eyebrow{\n    display: inline-flex; align-items: center; gap: 10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: rgba(255,255,255,.70);\n    margin-bottom: 16px;\n  }\n  .pr-cta-eyebrow::before{\n    content:\"\"; width: 7px; height: 7px; border-radius: 50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 0 5px rgba(143,188,143,.22);\n  }\n  .pr-cta-h2{\n    font-size: clamp(32px, 4.4vw, 56px);\n    line-height: 1.04;\n    letter-spacing: -0.025em;\n    color: #fff;\n    font-weight: 700;\n    margin: 0 auto 18px;\n    max-width: 22ch;\n    text-wrap: balance;\n  }\n  .pr-cta-h2 em{\n    font-style: normal;\n    position: relative;\n    color: #fff;\n  }\n  .pr-cta-h2 em::before{\n    content:\"\";\n    position: absolute;\n    left: -2px; right: -2px;\n    bottom: 0.06em;\n    height: 12px;\n    background: linear-gradient(90deg, rgba(179,139,109,.55), rgba(143,188,143,.50));\n    border-radius: 3px;\n    z-index: -1;\n    transform: skewX(-6deg);\n  }\n  .pr-cta-text{\n    font-size: 15px;\n    line-height: 1.65;\n    color: rgba(255,255,255,.78);\n    margin: 0 auto 28px;\n    max-width: 56ch;\n  }\n  .pr-cta-actions{\n    display: inline-flex; flex-wrap: wrap; align-items: center; justify-content: center; gap: 12px;\n  }\n  .pr-cta-pri{\n    display: inline-flex; align-items: center; gap: 12px;\n    padding: 16px 8px 16px 24px;\n    background: var(--cta);\n    color: #fff;\n    font-size: 14.5px;\n    font-weight: 600;\n    border-radius: 999px;\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.20) inset,\n      0 12px 32px -10px rgba(87,109,181,.60);\n    transition: transform .2s, background .2s, box-shadow .25s;\n  }\n  .pr-cta-pri:hover{\n    background: var(--cta-hover);\n    transform: translateY(-2px);\n    box-shadow: 0 1px 0 rgba(255,255,255,.20) inset, 0 18px 42px -10px rgba(87,109,181,.75);\n  }\n  .pr-cta-pri .ico{\n    width: 30px; height: 30px;\n    border-radius: 50%;\n    background: rgba(255,255,255,.20);\n    display: grid; place-items: center;\n    flex: 0 0 30px;\n    transition: background .25s, transform .3s;\n  }\n  .pr-cta-pri:hover .ico{ background: rgba(255,255,255,.30); transform: rotate(-12deg); }\n  .pr-cta-sec{\n    display: inline-flex; align-items: center; gap: 10px;\n    padding: 16px 24px;\n    background: rgba(255,255,255,.10);\n    border: 1px solid rgba(255,255,255,.20);\n    color: #fff;\n    font-size: 14.5px;\n    font-weight: 600;\n    border-radius: 999px;\n    transition: background .25s, border-color .25s, transform .2s;\n  }\n  .pr-cta-sec:hover{\n    background: rgba(255,255,255,.18);\n    border-color: rgba(255,255,255,.35);\n    transform: translateY(-2px);\n  }\n\n  /* Reveal */\n  .reveal{ opacity: 0; transform: translateY(14px); animation: rise .9s cubic-bezier(.2,.7,.2,1) forwards; }\n  .reveal.d1{ animation-delay: .05s; }\n  .reveal.d2{ animation-delay: .15s; }\n  .reveal.d3{ animation-delay: .25s; }\n  @keyframes rise{ to { opacity: 1; transform: none; } }\n\n  /* Responsive */\n  @media (max-width: 1100px){\n    .pr-includes-grid{ grid-template-columns: 1fr; }\n    .pr-tiers-grid{ grid-template-columns: 1fr; }\n    .pr-tier.is-featured{ transform: none; }\n    .pr-tier.is-featured:hover{ transform: translateY(-6px); }\n  }\n  @media (max-width: 1024px){\n    .menu{ display: none; }\n    .pr-h1{ grid-column: 1 / -1; }\n    .pr-meta, .pr-lede{ grid-column: 1 / -1; }\n    .pr-lede{ padding-top: 14px; }\n    .pr-section-h2, .pr-section-sub{ grid-column: 1 / -1; }\n    .pr-section-sub{ padding-top: 14px; padding-bottom: 0; }\n    .pr-roi-grid{ grid-template-columns: 1fr; }\n    .pr-compare-wrap{ overflow-x: auto; }\n    .pr-table{ min-width: 720px; }\n  }\n  @media (max-width: 720px){\n    .pr-roi-stats{ grid-template-columns: 1fr; }\n  }\n  @media (max-width: 640px){\n    .nav{ height: 64px; gap: 12px; }\n    .logo img{ height: 30px; }\n    .lang{ display: none; }\n  }\n\n/* ============ FOOTER ============ */\n  .footer{\n    position:relative;\n    background:\n      linear-gradient(180deg, rgba(248,249,250,.4), rgba(248,249,250,.95)),\n      radial-gradient(800px 420px at 88% 10%, rgba(143,188,143,.10), transparent 70%),\n      radial-gradient(720px 380px at 8% 92%, rgba(179,139,109,.08), transparent 70%),\n      var(--bg);\n    border-top: 1px solid var(--line-soft);\n    padding: clamp(72px, 9vw, 112px) 0 28px;\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n  }\n\n  .ft-grid{\n    display:grid;\n    grid-template-columns: 1.4fr 1fr 1fr 1.4fr;\n    gap: clamp(32px, 4vw, 56px) clamp(24px, 3vw, 40px);\n    position: relative;\n  }\n\n  /* Brand block */\n  .ft-brand{\n    display:flex; flex-direction:column;\n    gap: 22px;\n    max-width: 360px;\n  }\n  .ft-logo{ display:inline-block; }\n  .ft-logo img{\n    height: 38px;\n    width: auto;\n    display:block;\n  }\n  .ft-desc{\n    font-size: 14px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    max-width: 38ch;\n  }\n  .ft-social{\n    display:flex; gap: 10px;\n    margin-top: 4px;\n  }\n  .ft-social a{\n    width: 40px; height: 40px;\n    border-radius: 50%;\n    display:grid; place-items:center;\n    border: 1px solid var(--line-soft);\n    background: rgba(255,255,255,.55);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n    color: var(--heading);\n    transition: background .25s, border-color .25s, color .25s, transform .25s;\n  }\n  .ft-social a:hover{\n    background: var(--line);\n    border-color: var(--line);\n    color: #fff;\n    transform: translateY(-2px);\n  }\n\n  /* Link columns */\n  .ft-col{\n    display:flex; flex-direction:column;\n    gap: 18px;\n  }\n  .ft-h{\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--heading);\n    margin: 0;\n    display:inline-flex; align-items:center; gap:8px;\n  }\n  .ft-h::before{\n    content:\"\"; width:5px; height:5px; border-radius:50%;\n    background: var(--line);\n  }\n  .ft-list{\n    list-style:none;\n    margin:0; padding:0;\n    display:flex; flex-direction:column;\n    gap: 11px;\n  }\n  .ft-list a,\n  .ft-list .ft-text{\n    font-size: 13.5px;\n    line-height: 1.5;\n    color: var(--body);\n    text-decoration: none;\n    position: relative;\n    transition: color .2s;\n    display: inline-block;\n  }\n  .ft-list a::after{\n    content:\"\";\n    position:absolute;\n    left: 0; bottom: -2px;\n    width: 0; height: 1px;\n    background: var(--line);\n    transition: width .25s ease;\n  }\n  .ft-list a:hover{ color: var(--heading); }\n  .ft-list a:hover::after{ width: 100%; }\n\n  .ft-list .ft-text{ color: var(--body); }\n  .ft-list a.ft-text-link{ color: var(--body); }\n\n  /* Newsletter */\n  .ft-news{\n    margin-top: 8px;\n    padding-top: 22px;\n    border-top: 1px solid var(--line-faint);\n  }\n  .ft-news-h{\n    font-size: 14px;\n    font-weight: 700;\n    color: var(--heading);\n    margin: 0 0 6px;\n    letter-spacing: -0.01em;\n  }\n  .ft-news-p{\n    font-size: 12.5px;\n    color: var(--muted);\n    margin: 0 0 14px;\n    line-height: 1.5;\n  }\n  .ft-form{\n    display:flex; align-items:center;\n    background: rgba(255,255,255,.6);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    padding: 4px 4px 4px 6px;\n    gap: 4px;\n    transition: border-color .25s, background .25s;\n  }\n  .ft-form:focus-within{\n    border-color: var(--line);\n    background: #fff;\n  }\n  .ft-form input{\n    flex: 1;\n    border: 0;\n    background: transparent;\n    padding: 10px 14px;\n    font-size: 13px;\n    font-family: inherit;\n    color: var(--heading);\n    outline: 0;\n    min-width: 0;\n  }\n  .ft-form input::placeholder{ color: var(--muted); }\n  .ft-form button{\n    padding: 10px 18px;\n    border-radius: 999px;\n    background: var(--cta);\n    color: #fff;\n    font-size: 12.5px;\n    font-weight: 600;\n    letter-spacing: .02em;\n    cursor: pointer;\n    border: 0;\n    display:inline-flex; align-items:center; gap: 6px;\n    flex: 0 0 auto;\n    transition: background .2s, transform .15s;\n  }\n  .ft-form button:hover{ background: var(--cta-hover); transform: translateY(-1px); }\n\n  /* Bottom row */\n  .ft-bottom{\n    margin-top: clamp(56px, 7vw, 80px);\n    padding-top: 22px;\n    border-top: 1px solid var(--line-faint);\n    display:flex; justify-content:space-between; align-items:center;\n    gap: 16px;\n    flex-wrap: wrap;\n    font-size: 12.5px;\n    color: var(--muted);\n  }\n  .ft-bottom-links{\n    display:flex; gap: 22px;\n    flex-wrap: wrap;\n  }\n  .ft-bottom-links a{\n    color: var(--muted);\n    transition: color .2s;\n  }\n  .ft-bottom-links a:hover{ color: var(--heading); }\n\n  @media (max-width: 1024px){\n    .ft-grid{ grid-template-columns: 1fr 1fr; }\n    .ft-brand{ grid-column: 1 / -1; max-width: 480px; }\n  }\n  @media (max-width: 640px){\n    .ft-grid{ grid-template-columns: 1fr; gap: 36px; }\n    .ft-brand{ grid-column: auto; }\n    .ft-bottom{ flex-direction: column; align-items: flex-start; }\n  }";
